const items = $('Query Anomalies').all();

if (items.length === 0) {
  return [{ json: { message: 'Nenhuma anomalia detectada.' } }];
}

// Group by location
const byLocation = {};
for (const item of items) {
  const loc = item.json.location_name || item.json.location_id || 'Desconhecido';
  if (byLocation[loc] == null) {
    byLocation[loc] = [];
  }
  byLocation[loc].push(item.json);
}

const today = new Date().toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });

let msg = '*Alerta de Anomalias nos Anuncios* - ' + today + '\n';
msg += '━━━━━━━━━━━━━━━━━━━━━\n\n';

for (const [location, ads] of Object.entries(byLocation)) {
  msg += '*' + location + '* (' + ads.length + ' anomalia' + (ads.length > 1 ? 's' : '') + ')\n';
  for (const ad of ads) {
    const adName = ad.ad_name || 'Sem nome';
    const cplDelta = ad.cpl_delta_pct != null ? (ad.cpl_delta_pct > 0 ? '+' : '') + Number(ad.cpl_delta_pct).toFixed(1) + '%' : 'N/A';
    const ctrDelta = ad.ctr_delta_pct != null ? (ad.ctr_delta_pct > 0 ? '+' : '') + Number(ad.ctr_delta_pct).toFixed(1) + '%' : 'N/A';
    const cplVal = ad.cpl != null ? 'R$ ' + Number(ad.cpl).toFixed(2) : 'N/A';
    const reason = ad.anomaly_reason || '';

    msg += '  • *' + adName + '*\n';
    msg += '    CPL: ' + cplVal + ' (delta: ' + cplDelta + ')\n';
    msg += '    CTR delta: ' + ctrDelta + '\n';
    if (reason) {
      msg += '    Motivo: ' + reason + '\n';
    }
  }
  msg += '\n';
}

msg += '━━━━━━━━━━━━━━━━━━━━━\n';
msg += '_Total: ' + items.length + ' anuncio(s) com anomalia_';

return [{ json: { message: msg, anomaly_count: items.length, locations: Object.keys(byLocation).length } }];
